class StockService {
    static let shared = StockService()
    private let session = URLSession.shared
    private let apiKey = "YOUR_API_KEY"
    private let baseURL = "https://api.example.com"
    
    private init() {}
    
    func fetchStockData(symbol: String) -> AnyPublisher<Stock, Error> {
        guard let url = URL(string: "\(baseURL)/stock/\(symbol)") else {
            return Fail(error: URLError(.badURL))
                .eraseToAnyPublisher()
        }
        
        return session.dataTaskPublisher(for: url)
            .map(\.data)
            .decode(type: Stock.self, decoder: JSONDecoder())
            .receive(on: DispatchQueue.main)
            .eraseToAnyPublisher()
    }
    
    func executeTrade(trade: Trade) -> AnyPublisher<TradeResult, Error> {
        guard let url = URL(string: "\(baseURL)/trade") else {
            return Fail(error: URLError(.badURL))
                .eraseToAnyPublisher()
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = try? JSONEncoder().encode(trade)
        
        return session.dataTaskPublisher(for: request)
            .map(\.data)
            .decode(type: TradeResult.self, decoder: JSONDecoder())
            .receive(on: DispatchQueue.main)
            .eraseToAnyPublisher()
    }
}

